(()=>{const e=document.getElementById("dark-mode-container"),t=document.getElementById("dark-mode");localStorage.getItem("dark")&&(e.classList.add("dark"),t.checked=!0),document.addEventListener("DOMContentLoaded",(()=>{for(const e of document.querySelectorAll(".section"))e.onmouseover=()=>{const t=document.querySelector(".current");t.classList.remove("current"),t.classList.add("move"),e.classList.add("current")};t.onchange=()=>{t.checked?(e.classList.add("dark"),localStorage.setItem("dark","dark")):(e.classList.remove("dark"),localStorage.removeItem("dark"))}}))})();